solution_code:
#include <iostream>

void categorize(int x) {
    std::cout << "whole: " << x << "\n";
}

void categorize(double x) {
    std::cout << "fractional: " << x << "\n";
}

int main() {
    int n;
    double d;
    std::cin >> n >> d;
    categorize(n);
    categorize(d);
    return 0;
}

