solution_code:
#include <iostream>

void label(int x) {
    std::cout << "int: " << x << "\n";
}

void label(double x) {
    std::cout << "double: " << x << "\n";
}

int main() {
    int n;
    double d;
    std::cin >> n >> d;
    label(n);   // no cast needed — int variable matches int overload exactly
    label(d);
    return 0;
}
